{
  "query": "query DnsVolumeByDay($zoneTag: String!, $startDate: Date!, $endDate: Date!) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      byDate: dnsAnalyticsAdaptiveGroups(
        limit: 5000
        filter: { date_geq: $startDate, date_leq: $endDate }
        orderBy: [date_ASC]
      ) {
        dimensions { date }
        count
      }
    }
  }
}",
  "variables": {
    "zoneTag": "{{CF_ZONE_ID}}",
    "startDate": "{{START_DATE}}",
    "endDate": "{{END_DATE}}"
  }
}

