    "endDate": "{{END_DATE}}"
  }
}

{
  "query": "query AccountNXDOMAIN($accountTag: String!, $startDate: String!, $endDate: String!) {
  viewer {
    accounts(filter: { accountTag: $accountTag }) {
      dnsAnalyticsAdaptive(
        filter: {
          date_geq: $startDate
          date_leq: $endDate
          responseCode: "NXDOMAIN"
        }
        limit: 100
        orderBy: [datetime_DESC]
      ) {
        zoneTag
        queryName
        responseCode
        queryType
        datetime
      }
    }
  }
}",
  "variables": {
    "accountTag": "{{CF_ACCOUNT_ID}}",
    "startDate": "{{START_DATE}}",
    "endDate": "{{END_DATE}}"
  }
}
